oxy_webhelp_navlinks = {"azr_devops_add_orgs-d26997e31801":{"topics":[{"title":"Permission categories for Azure DevOps ","shortdesc":"<p class=\"shortdesc\">For the backup and recovery tasks associated with Azure DevOps organization,         projects, and repositories, <span class=\"ph\">RSC<\/span> requires specific permissions. <span class=\"ph\">RSC<\/span> groups these permissions into categories for granular management so that         you can include or exclude these categories as required.<\/p>","href":"azure_devops\/azr_devops_permission_categories.html","attributes":{"data-id":"azr_devops_permission_categories"},"menu":{"hasChildren":false},"tocID":"azr_devops_permission_categories-d26997e31817","next":"azr_devops_permission_categories-d26997e31817"},{"title":"Set up Exocompute for Azure DevOps","shortdesc":"<p class=\"shortdesc\">With the Exocompute on Azure feature, <span class=\"ph\">RSC<\/span> launches an Azure         Kubernetes Service cluster to perform backup and recovery  operations to protect Azure         DevOps organizations. <span class=\"ph\">RSC<\/span> uses the Azure Kubernetes Service cluster to serve         as a compute resource in your Azure DevOps organization.<\/p>","href":"azure_devops\/azr_devops_set_up_exocompute.html","attributes":{"data-id":"azr_devops_set_up_exocompute"},"menu":{"hasChildren":false},"tocID":"azr_devops_set_up_exocompute-d26997e31858","topics":[]},{"title":"Set up backup location for Azure DevOps","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> protects your Azure DevOps organizations, projects, and         repositories. You can set up a backup location in Azure for storing the snapshots of Azure         DevOps organizations, projects, and repositories.<\/p>","href":"azure_devops\/azr_devops_set_up_backup_loc.html","attributes":{"data-id":"azr_devops_set_up_backup_loc"},"menu":{"hasChildren":false},"tocID":"azr_devops_set_up_backup_loc-d26997e31875","next":"azr_devops_set_up_backup_loc-d26997e31875"},{"title":"Adding Azure DevOps organization","shortdesc":"<p class=\"shortdesc\">Add Azure DevOps organization to <span class=\"ph\">RSC<\/span> to back up and recover         repositories, manage organizations, and minimize downtime.<\/p>","href":"azure_devops\/azure_devops_adding_orgs.html","attributes":{"data-id":"azure_devops_adding_orgs"},"menu":{"hasChildren":false},"tocID":"azure_devops_adding_orgs-d26997e31984","topics":[]},{"title":"Manage Azure DevOps organization","href":"azure_devops\/azure_devops_edit_org.html","menu":{"hasChildren":false},"tocID":"tocId-d26997e31998","next":"tocId-d26997e31998"}]}};